package org.apache.commons.csv;
import static org.apache.commons.csv.Constants.BACKSLASH;
import static org.apache.commons.csv.Constants.COMMA;
import static org.apache.commons.csv.Constants.COMMENT;
import static org.apache.commons.csv.Constants.EMPTY;
import static org.apache.commons.csv.Constants.CR;
import static org.apache.commons.csv.Constants.CRLF;
import static org.apache.commons.csv.Constants.DOUBLE_QUOTE_CHAR;
import static org.apache.commons.csv.Constants.LF;
import static org.apache.commons.csv.Constants.PIPE;
import static org.apache.commons.csv.Constants.SP;
import static org.apache.commons.csv.Constants.TAB;
import java.io.File;
import java.io.FileOutputStream;
import java.io.IOException;
import java.io.OutputStreamWriter;
import java.io.Reader;
import java.io.Serializable;
import java.io.StringWriter;
import java.nio.charset.Charset;
import java.nio.file.Files;
import java.nio.file.Path;
import java.sql.ResultSet;
import java.sql.ResultSetMetaData;
import java.sql.SQLException;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testGetRecordSeparator_Default() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertEquals("\r\n", format.getRecordSeparator());
    }

    @Test
    void testGetRecordSeparator_Excel() {
        CSVFormat format = CSVFormat.EXCEL;
        assertEquals("\r\n", format.getRecordSeparator());
    }

    @Test
    void testGetRecordSeparator_InformixUnload() {
        CSVFormat format = CSVFormat.INFORMIX_UNLOAD;
        assertEquals("\n", format.getRecordSeparator());
    }

    @Test
    void testGetRecordSeparator_InformixUnloadCsv() {
        CSVFormat format = CSVFormat.INFORMIX_UNLOAD_CSV;
        assertEquals("\n", format.getRecordSeparator());
    }

    @Test
    void testGetRecordSeparator_Mysql() {
        CSVFormat format = CSVFormat.MYSQL;
        assertEquals("\n", format.getRecordSeparator());
    }

    @Test
    void testGetRecordSeparator_PostgresqlCsv() {
        CSVFormat format = CSVFormat.POSTGRESQL_CSV;
        assertEquals("\n", format.getRecordSeparator());
    }

    @Test
    void testGetRecordSeparator_PostgresqlText() {
        CSVFormat format = CSVFormat.POSTGRESQL_TEXT;
        assertEquals("\n", format.getRecordSeparator());
    }

    @Test
    void testGetRecordSeparator_Rfc4180() {
        CSVFormat format = CSVFormat.RFC4180;
        assertEquals("\r\n", format.getRecordSeparator());
    }

    @Test
    void testGetRecordSeparator_Tdf() {
        CSVFormat format = CSVFormat.TDF;
        assertEquals("\r\n", format.getRecordSeparator());
    }

    @Test
    void testGetRecordSeparator_WithCustomRecordSeparator() {
        CSVFormat format = CSVFormat.DEFAULT.withRecordSeparator("\r");
        assertEquals("\r", format.getRecordSeparator());
    }

    @Test
    void testGetRecordSeparator_WithNullRecordSeparator() throws Exception {
        // Use reflection to create a CSVFormat instance with recordSeparator set to null
        CSVFormat defaultFormat = CSVFormat.DEFAULT;
        java.lang.reflect.Constructor<CSVFormat> constructor = CSVFormat.class.getDeclaredConstructor(
            char.class, Character.class, QuoteMode.class, Character.class, Character.class,
            boolean.class, boolean.class, String.class, String.class, Object[].class,
            String[].class, boolean.class, boolean.class, boolean.class, boolean.class,
            boolean.class, boolean.class);
        constructor.setAccessible(true);
        CSVFormat format = constructor.newInstance(
            defaultFormat.getDelimiter(),
            defaultFormat.getQuoteCharacter(),
            defaultFormat.getQuoteMode(),
            defaultFormat.getCommentMarker(),
            defaultFormat.getEscapeCharacter(),
            defaultFormat.getIgnoreSurroundingSpaces(),
            defaultFormat.getIgnoreEmptyLines(),
            null, // recordSeparator set to null
            defaultFormat.getNullString(),
            null,
            defaultFormat.getHeader(),
            defaultFormat.getSkipHeaderRecord(),
            defaultFormat.getAllowMissingColumnNames(),
            defaultFormat.getIgnoreHeaderCase(),
            defaultFormat.getTrim(),
            defaultFormat.getTrailingDelimiter(),
            defaultFormat.getAutoFlush()
        );
        assertNull(format.getRecordSeparator());
    }
}
